const express = require('express');
const app = express();
const PORT = process.env.PORT || 3000;

// Middleware to log requests including API keys
app.use((req, res, next) => {
    const apiKey = req.query.api_key;
    console.log(`Request received at ${new Date()}. API Key: ${apiKey}`);
    next();
});

// Middleware to authenticate using API key
const authenticate = (req, res, next) => {
    const apiKey = req.query.api_key;
    if (!apiKey) {
        return res.status(401).json({ error: 'API key is missing' });
    }
    // Replace with actual validation logic
    if (apiKey !== 'valid_api_key') {
        return res.status(403).json({ error: 'Invalid API key' });
    }
    next();
};

// Example route that forwards requests to a backend service
app.get('/proxy', authenticate, (req, res) => {
    const backendUrl = 'http://backend-service.com/api';
    const apiKey = req.query.api_key;

    // Forward the request with the API key in the header
    fetch(backendUrl, {
        method: 'GET',
        headers: {
            'API-Key': apiKey,
            'Content-Type': 'application/json'
        }
    })
    .then(response => response.json())
    .then(data => res.json(data))
    .catch(error => res.status(500).json({ error: 'Error forwarding request' }));
});

app.listen(PORT, () => {
    console.log(`API Gateway is running on port ${PORT}`);
});